import{_ as e,o,c as n,ac as r}from"./chunks/framework.DnBnwVZk.js";const S=JSON.parse('{"title":"SpringBoot源码-App启动过程","description":"","frontmatter":{"date":"2020-03-29T00:00:00.000Z","categories":["Spring"],"tag":["SpringBoot","源码"]},"headers":[],"relativePath":"views/spring/2020/SpringBootAppStart.md","filePath":"views/spring/2020/SpringBootAppStart.md","lastUpdated":1775714960000}'),t={name:"views/spring/2020/SpringBootAppStart.md"};function l(a,i,p,s,c,g){return o(),n("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1585440000000"},[...i[0]||(i[0]=[r('<h1 id="springboot源码-app启动过程" tabindex="-1">SpringBoot源码-App启动过程 <a class="header-anchor" href="#springboot源码-app启动过程" aria-label="Permalink to &quot;SpringBoot源码-App启动过程&quot;">​</a></h1><h2 id="_1-整体流程" tabindex="-1">1. 整体流程 <a class="header-anchor" href="#_1-整体流程" aria-label="Permalink to &quot;1. 整体流程&quot;">​</a></h2><ol><li>a = new SpringApplication(primarySources)</li><li>a.run</li></ol><h3 id="_1-1-初始化springapplication实例" tabindex="-1">1.1 初始化SpringApplication实例 <a class="header-anchor" href="#_1-1-初始化springapplication实例" aria-label="Permalink to &quot;1.1 初始化SpringApplication实例&quot;">​</a></h3><ol><li>判断webApplicationType:通过尝试使用ClassLoader加载对应的标识类来判断WebApp类型，首先判断WEBFLUX,然后根据javax.servlet.Servlet类和WebApplicationContext类判断是否Servlet,都不是则返回None</li><li>加载所有Jar包中META-INF/spring.facotry文件定义的工厂类：</li><li>初始化ApplicationContextInitializer类型实例</li><li>初始化ApplicationListener实例</li><li>获取MainApplicationClass：通过从调用栈中获取main方法所在的类来获取</li></ol><h3 id="_1-2-启动初始化完成的springapplication" tabindex="-1">1.2 启动初始化完成的SpringApplication <a class="header-anchor" href="#_1-2-启动初始化完成的springapplication" aria-label="Permalink to &quot;1.2 启动初始化完成的SpringApplication&quot;">​</a></h3><ol><li>开启计时器</li><li>设置java.awt.headless：Headless模式是系统的一种配置模式。在该模式下，系统缺少了显示设备、键盘或鼠标。</li><li>初始化并启动配置的SpringApplicationRunListeners类型实例: <ol><li>SpringBoot包定义一个EventPublishingRunListener实现，此实现在构造过程中会在内部初始化SimpleApplicationEventMulticaster实例：</li><li>广播ApplicationStartingEvent事件到相应的Listener： <ul><li>LoggingApplicationListener：加载log实现，顺序：org.springframework.boot.logging.LoggingSystem定义&gt;logback&gt;log4j&gt;jul</li><li>BackgroundPreinitializer: 提前开始初始化耗时的Bean如Conversion、Jackson等Bean</li><li>DelegatingApplicationListener：无操作</li><li>LiquibaseServiceLocatorApplicationListener：无操作</li></ul></li></ol></li><li>Prepare Environment实例： <ol><li>初始化PropertySources：servletConfigInitParams,servletContextInitParams,systemProperties,systemEnvironment</li><li>初始化ConversionService: 使用ApplicationConversionService实例</li><li>读取Profile</li><li>Environment Prepare完成，广播ApplicationEnvironmentPreparedEvent事件,调用所有的ApplicationListener，调用对应方法，下面仅挑选重点的几个： <ul><li>ConfigFileApplicationListener: 见#### 1.2.1 Config文件加载</li><li>LoggingApplicationListener：处理Logger相关</li></ul></li><li>Bind过程----&gt;todo</li><li>自定义Environment转换为标准Environment</li><li>新增一个ConfigurationPropertySources</li></ol></li><li>设置spring.beaninfo.ignore，默认为true，即跳过BeanInfo检测</li><li>打印Banner</li><li>创建上下文：ApplicationContext：对于SERVLET模式,实际初始化AnnotationConfigServletWebServerApplicationContext对象，见<a href="./SpringBootWebContext.html">AnnotationConfigServletWebServerApplicationContext 源码解读</a></li><li>创建SpringBootExceptionReporter实例 <ul><li>org.springframework.boot.diagnostics.FailureAnalyzers</li></ul></li><li>prepare上下文，见<a href="./SpringBootWebContext.html">AnnotationConfigServletWebServerApplicationContext 源码解读</a></li><li>refresh上下文，见<a href="./SpringBootWebContext.html">AnnotationConfigServletWebServerApplicationContext 源码解读</a></li><li>afterRefresh,默认无操作</li></ol><h4 id="_1-2-1-config文件加载" tabindex="-1">1.2.1 Config文件加载 <a class="header-anchor" href="#_1-2-1-config文件加载" aria-label="Permalink to &quot;1.2.1 Config文件加载&quot;">​</a></h4><p>时机：EnvironmentPrepared事件发布后 类：ConfigFileApplicationListener</p><ol><li>读取EnvironmentPostProcessor列表，并分别调用： <ul><li>SystemEnvironmentPropertySourceEnvironmentPostProcessor：将Environment中的SystemEnvironmentPropertySource替换成OriginAwareSystemEnvironmentPropertySource</li><li>SpringApplicationJsonEnvironmentPostProcessor：处理spring.application.json数据为Spring数据源，来源包括环境变量（SPRING_APPLICATION_JSON），系统属性或者properties定义</li><li>CloudFoundryVcapEnvironmentPostProcessor：处理云环境的VCAP数据</li><li>ConfigFileApplicationListener：见1.2.1.1，配置文件加载到Environment</li></ul></li></ol><h5 id="_1-2-1-1-配置文件加载到environment" tabindex="-1">1.2.1.1 配置文件加载到Environment <a class="header-anchor" href="#_1-2-1-1-配置文件加载到environment" aria-label="Permalink to &quot;1.2.1.1 配置文件加载到Environment&quot;">​</a></h5><ul><li>时机：EnvironmentPrepared事件广播-&gt;调用ApplicationListener-&gt;调用ConfigFileApplicationListener的onApplicationEvent方法-&gt;加载并调用所有的EnvironmentPostProcessor类型的实例的postProcessEnvironment方法-&gt;ConfigFileApplicationListener实例本身属于EnvironmentPostProcessor类，调用其postProcessEnvironment方法</li><li>方法：ConfigFileApplicationListener实例的postProcessEnvironment方法</li><li>过程：</li></ul><ol><li>初始化Loader实例: <ol><li>初始化placeholdersResolver：<code>new PropertySourcesPlaceholdersResolver(this.environment);</code></li><li>初始化resourceLoader：<code>new DefaultResourceLoader();</code></li><li>初始化propertySourceLoaders：<code>SpringFactoriesLoader.loadFactories(PropertySourceLoader.class, getClass().getClassLoader())</code>： <ul><li>org.springframework.boot.env.PropertiesPropertySourceLoader</li><li>org.springframework.boot.env.YamlPropertySourceLoader</li></ul></li></ol></li><li>调用Loader.load()方法 <ol><li>获取Active Profile：读取PropertySource(到当前阶段，主要还是SystemProperties和SystemEnvironment值)的spring.profiles.active和spring.profiles.include的配置</li><li>根据profile读取配置文件: <ul><li>位置： <ol><li>环境变量中spring.config.location配置的位置</li><li>环境变量中spring.config.additional-location配置的位置</li><li>预设的位置：<strong>注意，由于有reverse操作，所以最后一个为先</strong>：classpath:/,classpath:/config/,file:./,file:./config/，</li></ol></li><li>加载策略： <ol><li>如果有spring.config.name定义，则加载定义的文件名，否则加载文件名由application开头的文件</li><li>调用所有的PropertySourceLoader，处理所有其定义的文件后缀对应的文件，对于默认情况，分别有两个默认加载器，其中Properties加载器负责加载</li></ol></li></ul></li></ol></li></ol>',13)])])}const m=e(t,[["render",l]]);export{S as __pageData,m as default};
